INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 2, 0.0, "アヤネ", 0.0, "2030/12/17 14:59:59", "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 24001, "2020/07/31 12:00:00", 401, 102301);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "アヤネ", 2.21, "2030/12/17 14:59:59", "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 24002, "2020/07/31 12:00:00", 402, 102301);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 2, 0.0, "アヤネ", 0.0, "2030/12/17 14:59:59", "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 24003, "2020/07/31 12:00:00", 403, 102301);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 1, 0.0, "アサヒ", 1.99, "2030/12/17 14:59:59", "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 24004, "2020/07/31 12:00:00", 701, 192201);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "アサヒ", 2.21, "2030/12/17 14:59:59", "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 24005, "2020/07/31 12:00:00", 702, 192201);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 1, 0.0, "アサヒ", 3.33, "2030/12/17 14:59:59", "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 24006, "2020/07/31 12:00:00", 703, 192201);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 2, 0.0, "部員３", 0.0, "2030/12/17 14:59:59", "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 24007, "2020/07/31 12:00:00", 801, 192301);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "部員３", 2.68, "2030/12/17 14:59:59", "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 24008, "2020/07/31 12:00:00", 802, 192301);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 2, 0.0, "部員３", 0.0, "2030/12/17 14:59:59", "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 24009, "2020/07/31 12:00:00", 803, 192301);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 1, 0.0, "", 0.0, "2030/12/17 14:59:59", "やった！", 24010, "2020/07/31 12:00:00", 501, 192501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 1, 0.0, "", 0.0, "2030/12/17 14:59:59", "勝ったよ！", 24011, "2020/07/31 12:00:00", 502, 192501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 1, 0.0, "", 0.0, "2030/12/17 14:59:59", "いい調子！", 24012, "2020/07/31 12:00:00", 503, 192501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (6, 24, 0.0, 10046, 2, 0.0, "ミサト", 5.33, "2030/12/17 14:59:59", "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 24013, "2020/07/31 12:00:00", 111, 113501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "ミサト", 6.85, "2030/12/17 14:59:59", "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 24014, "2020/07/31 12:00:00", 112, 113501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "ミサト", 3.0, "2030/12/17 14:59:59", "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 24015, "2020/07/31 12:00:00", 113, 113501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "ダイチ", 6.11, "2030/12/17 14:59:59", "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 24016, "2020/07/31 12:00:00", 611, 192401);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "ダイチ", 6.75, "2030/12/17 14:59:59", "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 24017, "2020/07/31 12:00:00", 612, 192401);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 2, 0.0, "ダイチ", 0.0, "2030/12/17 14:59:59", "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 24018, "2020/07/31 12:00:00", 613, 192401);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 1, 0.0, "ハツネ", 4.52, "2030/12/17 14:59:59", "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 24019, "2020/07/31 12:00:00", 211, 113401);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 1, 0.0, "ハツネ", 3.89, "2030/12/17 14:59:59", "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 24020, "2020/07/31 12:00:00", 212, 113401);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "ハツネ", 13.49, "2030/12/17 14:59:59", "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 24021, "2020/07/31 12:00:00", 213, 113401);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "カヤ", 3.17, "2030/12/17 14:59:59", "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 24022, "2020/07/31 12:00:00", 311, 106501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 2, 0.0, "カヤ", 4.42, "2030/12/17 14:59:59", "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 24023, "2020/07/31 12:00:00", 312, 106501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (6, 24, 0.0, 10046, 1, 0.0, "カヤ", 2.89, "2030/12/17 14:59:59", "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 24024, "2020/07/31 12:00:00", 313, 106501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (4, 24, 0.0, 10046, 3, 0.0, "アヤネ", 3.71, "2030/12/17 14:59:59", "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 24025, "2020/07/31 12:00:00", 421, 102301);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, 0.0, 10046, 1, 0.0, "アサヒ", 5.1, "2030/12/17 14:59:59", "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 24026, "2020/07/31 12:00:00", 721, 192201);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 3, 0.0, "部員３", 4.34, "2030/12/17 14:59:59", "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 24027, "2020/07/31 12:00:00", 821, 192301);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, 0.0, 10046, 1, 0.0, "", 0.0, "2030/12/17 14:59:59", "いい勝負だったよ\nまたやろうね", 24028, "2020/07/31 12:00:00", 521, 192501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, -360.0, 10046, 2, 0.0, "ミサト", 5.62, "2030/12/17 14:59:59", "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 24029, "2020/07/31 12:00:00", 101, 113501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, -360.0, 10046, 2, 0.0, "ミサト", 9.58, "2030/12/17 14:59:59", "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 24030, "2020/07/31 12:00:00", 102, 113501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, -360.0, 10046, 2, 0.0, "ミサト", 0.0, "2030/12/17 14:59:59", "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 24031, "2020/07/31 12:00:00", 103, 113501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (2, 24, -360.0, 10046, 1, 0.0, "ミサト", 9.13, "2030/12/17 14:59:59", "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 24032, "2020/07/31 12:00:00", 104, 113501);
INSERT INTO `v1_9229f9b0566df6b6d6f1b32ece767a21ac8b8f755d8bd32cbe7aada94ac7e068` VALUES (1, 24, -360.0, 10046, 2, 0.0, "ミサト", 8.27, "2030/12/17 14:59:59", "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 24033, "2020/07/31 12:00:00", 105, 113501);
